template <typename K = ull, typename V = int, int SIZE = 1 << 20, bool MIX_KEYS = true>
class FastHashMap {
    /**
    * 【开放寻址哈希表使用事项】
    * 不支持删除/修改单个 key，不如自带的哈希表灵活
    * 255 次溢出 clear 触发一次 memset，使用了 gen+tag 进行优化，避免每个单例都 memset
    * 表满了会卡住，建议 key 的数量远小于 SIZE
    * 注意 key 本身是否为分布均匀的哈希值，若是则 MIX_KEYS 设为 false（如字符串哈希、双哈希拼成的 ull、坐标编码后哈希等），否则启用 mix
    * K 的类型只能是小于 8 字节的，所以能用的为 int ll ull pii
    * V 的类型随意
    */

    static_assert((SIZE & (SIZE - 1)) == 0, "SIZE 必须是 2 的幂次");

    K keys[SIZE];
    V values[SIZE];
    uint8_t gen[SIZE]{};
    uint8_t tag = 1;

    static ull mix(ull x) {
        x ^= x >> 30;
        x *= 0xbf58476d1ce4e5b9ULL;
        x ^= x >> 27;
        x *= 0x94d049bb133111ebULL;
        x ^= x >> 31;
        return x;
    }

    int hash(K key) {
        ull x = 0;
        if constexpr (is_same_v<K, ull>)x = key; // 本来就是 ull，直接赋值
        else if constexpr (is_same_v<K, ll>)x = static_cast<ull>(key); // ll 也能直接转，跳过 memcpy
        else memcpy(&x, &key, sizeof(K)); // 其他类型才 memcpy

        if constexpr (MIX_KEYS) x = mix(x);
        return x & (SIZE - 1);
    }

public:
    void clear() {
        // gen + tag 实现更快的清空
        if (++tag == 0) { // 溢出, 256 次 clear 才触发一次
            memset(gen, 0, sizeof(gen));
            tag = 1;
        }
    }

    void insert(K key, V val) {
        int h = hash(key);
        while (gen[h] == tag && keys[h] != key)
            h = (h + 1) & (SIZE - 1);
        gen[h] = tag;
        keys[h] = key;
        values[h] = val;
    }

    V get(K key) {
        int h = hash(key);
        while (gen[h] == tag) {
            if (keys[h] == key) return values[h];
            h = (h + 1) & (SIZE - 1);
        }
        return {}; // 没查到
    }
};

int hs1[N], p1[N], hs2[N], p2[N];
const int base1 = 131, base2 = 13331;
const int M1 = 1e9 + 7, M2 = 1e9 + 9;
pll ans[3 * N];
string Q[3 * N];
ll a[N], pre[N], prepre[N], premn[N], sufmx[N];
vector<int> pos[3 * N];
FastHashMap<ull, int, 1 << 20, false> mp;
void solve(int CASE)
{
    int n, q; cin >> n >> q;
    fa(i, 1, q)ans[i].px = -4e18;
    sufmx[n + 1] = -4e18;
    string s; cin >> s; s = ' ' + s;

    // 双哈希
    p1[0] = p2[0] = 1;
    fa(i, 1, n) {
        hs1[i] = (1ll * hs1[i - 1] * base1 + s[i] - 'a' + 1) % M1;
        p1[i] = 1ll * p1[i - 1] * base1 % M1;
        hs2[i] = (1ll * hs2[i - 1] * base2 + s[i] - 'a' + 1) % M2;
        p2[i] = 1ll * p2[i - 1] * base2 % M2;
    }
    var get = [&](int l, int r)->ull { 
        int res1 = (hs1[r] - 1ll * hs1[l - 1] * p1[r - l + 1] % M1 + M1) % M1;
        int res2 = (hs2[r] - 1ll * hs2[l - 1] * p2[r - l + 1] % M2 + M2) % M2;
        return (ull)res1 << 32 | res2; 
        };

    fa(i, 1, n)cin >> a[i], pre[i] = pre[i - 1] + a[i];
    fa(i, 1, n)prepre[i] = (prepre[i - 1] + pre[i] % mod) % mod, premn[i] = min(premn[i - 1], pre[i]);
    fb(i, n, 1)sufmx[i] = max(sufmx[i + 1], pre[i]);

    var lens = vector<int>();
    fa(i, 1, q) {
        cin >> Q[i];
        lens.pb(Q[i].size());

        // 获取当前双哈希
        int qhs1 = 0, qhs2 = 0;
        for (char c : Q[i]) {
            qhs1 = (1ll * qhs1 * base1 + c - 'a' + 1) % M1;
            qhs2 = (1ll * qhs2 * base2 + c - 'a' + 1) % M2;
        }
        ull qhs = (ull)qhs1 << 32 | qhs2;

        // 处理重复询问的
        if (mp.get(qhs) == 0)mp.insert(qhs, i);
        else ans[i] = { mp.get(qhs), -1 }; // 重复打上 -1 标记
    }
    sort(all(lens));
    lens.erase(unique(all(lens)), lens.end());

    // 长度总数不会超过 根号 n 个
    // 此处使用超强哈希表，复杂度为 O(n 根号 n)
    for (int len : lens) {
        fa(r, len, n) {
            int l = r - len + 1;
            ull now = get(l, r);
            int id = mp.get(now);
            if (id == 0) continue;
            ans[id].px = max(ans[id].px, sufmx[r] - premn[l - 1]);
            pos[id].pb(l);
        }
    }

    // 用 pos 提取全部区间统一处理从而规避重复计算（原理画图就能懂）
    // 此处最坏情况全为 aaaa，复杂度为 O(n 根号 n)
    fa(i, 1, q)if (ans[i].py != -1) {
        ll len = Q[i].size();
        ll lastl = 0;
        for (ll l : pos[i]) {
            ll r = l + len - 1;
            ll sum =
                ((prepre[n] - prepre[r - 1]) % mod + mod) % mod * (l - lastl) % mod
                -
                ((prepre[l - 1] - (lastl > 0 ? prepre[lastl - 1] : 0)) % mod + mod) % mod * (n - r + 1) % mod;
            sum = (sum + mod) % mod;
            ans[i].py = (ans[i].py + sum) % mod;
            lastl = l;
        }
    }

    fa(i, 1, q) {
        if (ans[i].py != -1)cout << ans[i].px << " " << ans[i].py << endl;
        else cout << ans[ans[i].px].px << ' ' << ans[ans[i].px].py << endl;
    }
    return;
}
